import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.stream.JsonWriter;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.InOrder;

import java.io.IOException;
import java.io.StringWriter;
import java.io.Writer;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

public class JsonWriterTest {

  private JsonWriter jsonWriter;
  private StringWriter stringWriter;

  @BeforeEach
  public void setUp() {
    stringWriter = new StringWriter();
    jsonWriter = new JsonWriter(stringWriter);
  }

  @Test
  public void testOpen_emptyArray() throws Exception {
    invokeOpenAndVerify(EMPTY_ARRAY, '[');
  }

  @Test
  public void testOpen_emptyObject() throws Exception {
    invokeOpenAndVerify(EMPTY_OBJECT, '{');
  }

  // Helper to invoke private open(int, char) and verify behavior
  private void invokeOpenAndVerify(int empty, char openBracket)
      throws NoSuchMethodException, InvocationTargetException, IllegalAccessException, IOException {
    // Use reflection to get private open method
    Method openMethod = JsonWriter.class.getDeclaredMethod("open", int.class, char.class);
    openMethod.setAccessible(true);

    // Spy on the JsonWriter to verify beforeValue and push are called
    JsonWriter spyWriter = spy(jsonWriter);

    // Because open is private and uses beforeValue and push, we verify those calls
    Method beforeValueMethod = JsonWriter.class.getDeclaredMethod("beforeValue");
    beforeValueMethod.setAccessible(true);
    doNothing().when(spyWriter).beforeValue();

    Method pushMethod = JsonWriter.class.getDeclaredMethod("push", int.class);
    pushMethod.setAccessible(true);
    doNothing().when(spyWriter).push(empty);

    // Invoke open on spyWriter
    JsonWriter result = (JsonWriter) openMethod.invoke(spyWriter, empty, openBracket);

    // Verify beforeValue and push called once with correct argument
    verify(spyWriter, times(1)).beforeValue();
    verify(spyWriter, times(1)).push(empty);

    // Verify output written contains the openBracket character
    String output = stringWriter.toString();
    // Because open writes to out, but we spied on jsonWriter, the stringWriter should contain openBracket
    // However, spyWriter's out is the same as jsonWriter's out, so output should contain openBracket
    assertTrue(output.indexOf(openBracket) >= 0);

    // Result should be the spyWriter itself (this)
    assertSame(spyWriter, result);
  }

  // Constants from JsonScope to use in tests
  private static final int EMPTY_ARRAY = 1;
  private static final int EMPTY_OBJECT = 3;
}
